def conditionalProcess: UserDefinedFunction = udf((bytes: Array[Byte]) => {
  val ds = loadDataset(bytes)

  try {
    // Check condition using execute method
    val numBands = RST_NumBands.execute(ds)

    if (numBands >= 4) {
      // Process multispectral
      processMultispectral(ds)
    } else {
      // Process RGB
      processRGB(ds)
    }
  } finally {
    ds.delete()
  }
})

def chainedProcessing: UserDefinedFunction = udf((bytes: Array[Byte]) => {
  val ds = loadDataset(bytes)

  try {
    // Step 1: Extract info
    val metadata = RST_MetaData.execute(ds)

    // Step 2: Validate
    val isValid = validateMetadata(metadata)

    if (isValid) {
      // Step 3: Process
      val bbox = RST_BoundingBox.execute(ds)
      val clipped = clipToAOI(ds, bbox)

      // Step 4: Serialize result
      serializeRaster(clipped)
    } else {
      Array.empty[Byte]
    }
  } finally {
    ds.delete()
  }
})

