from databricks.labs.gbx.rasterx import functions as rx
from pyspark.sql import functions as f
import json

# Simple addition of two rasters
df = spark.createDataFrame([
    (1, "/data/raster1.tif"),
    (2, "/data/raster2.tif")
], ["id", "path"]).select(
    f.collect_list(
        rx.rst_fromfile(f.col("path"), f.lit("GTiff"))
    ).alias("tiles")
)

# Add rasters A + B
addition_spec = json.dumps({
    "calc": "A+B",
    "A_index": 0,  # First raster in array
    "B_index": 1   # Second raster in array
})

sum_raster = df.select(
    rx.rst_mapalgebra(f.col("tiles"), f.lit(addition_spec)).alias("sum")
)

# Calculate NDVI: (NIR - Red) / (NIR + Red)
# Using a multi-band raster
ndvi_spec = json.dumps({
    "calc": "(A-B)/(A+B)",
    "A_index": 0,
    "A_band": 4,  # NIR band
    "B_index": 0,
    "B_band": 3   # Red band
})

ndvi = df.select(
    rx.rst_mapalgebra(f.col("tiles"), f.lit(ndvi_spec)).alias("ndvi")
)

# Difference of rasters
difference_spec = json.dumps({
    "calc": "A-B",
    "A_index": 0,
    "B_index": 1
})

diff = df.select(
    rx.rst_mapalgebra(f.col("tiles"), f.lit(difference_spec)).alias("difference")
)

# Conditional expression: Set values < 0 to 0
conditional_spec = json.dumps({
    "calc": "numpy.where(A<0, 0, A)",
    "A_index": 0
})

clipped = df.select(
    rx.rst_mapalgebra(f.col("tiles"), f.lit(conditional_spec)).alias("clipped")
)

# Complex calculation: Enhanced Vegetation Index (EVI)
# EVI = 2.5 * (NIR - Red) / (NIR + 6*Red - 7.5*Blue + 1)
evi_spec = json.dumps({
    "calc": "2.5 * (A - B) / (A + 6*B - 7.5*C + 1)",
    "A_index": 0,
    "A_band": 5,  # NIR
    "B_index": 0,
    "B_band": 4,  # Red
    "C_index": 0,
    "C_band": 2   # Blue
})

evi = df.select(
    rx.rst_mapalgebra(f.col("tiles"), f.lit(evi_spec)).alias("evi")
)

# Logarithmic transformation
log_spec = json.dumps({
    "calc": "numpy.log10(A+1)",  # +1 to avoid log(0)
    "A_index": 0
})

log_transformed = df.select(
    rx.rst_mapalgebra(f.col("tiles"), f.lit(log_spec)).alias("log")
)

# Threshold and classify
threshold_spec = json.dumps({
    "calc": "numpy.where(A>100, 1, numpy.where(A>50, 2, 3))",
    "A_index": 0
})

classified = df.select(
    rx.rst_mapalgebra(f.col("tiles"), f.lit(threshold_spec)).alias("classes")
)

